### Step 7: Update cmd_serve to use factory

```rust
async fn cmd_serve() -> Result<()> {
    let config = load_config()?;
    let store = Arc::from(connect_store(&config).await?);
    let engine: Arc<dyn InferenceEngine> = Arc::from(connect_engine(&config));

    let state = Arc::new(corvia_server::rest::AppState { store, engine });
    let app = corvia_server::rest::router(state);

    let addr = format!("{}:{}", config.server.host, config.server.port);
    println!("Corvia server listening on {addr}");
    let listener = tokio::net::TcpListener::bind(&addr).await?;
    axum::serve(listener, app).await?;
    Ok(())
}
